using SkiaSharp;
using Svg.Skia;
using System;
using System.IO;
using System.Text;

using var surface = SKSurface.Create(new SKImageInfo(10, 10));
var c = surface.Canvas;
c.Clear(SKColors.Red);
using var img = surface.Snapshot();
using var pngData = img.Encode(SKEncodedImageFormat.Png, 100);
var base64 = Convert.ToBase64String(pngData.ToArray());

var svgContent = $@"<svg width=""70mm"" height=""50mm"" viewBox=""0 0 265 189"" xmlns=""http://www.w3.org/2000/svg"">
  <rect x=""5"" y=""5"" width=""255"" height=""179"" fill=""none"" stroke=""black""/>
  <image href=""data:image/png;base64,{base64}"" x=""10"" y=""22"" width=""40"" height=""20"" preserveAspectRatio=""xMidYMid meet""/>
  <text x=""10"" y=""60"" font-size=""12"">Test Text</text>
</svg>";

using var ms = new MemoryStream(Encoding.UTF8.GetBytes(svgContent));
var skSvg = new SKSvg();
var picture = skSvg.Load(ms);
var bounds = picture.CullRect;
const float contentScale = 72f / 96f;
var pageWidth = bounds.Width * contentScale;
var pageHeight = bounds.Height * contentScale;

using (var pdfStream = File.Create("output.pdf"))
{
    using var pdfDoc = SKDocument.CreatePdf(pdfStream);
    if (pdfDoc == null) { Console.WriteLine("FAILURE: CreatePdf null"); return; }
    using var canvas = pdfDoc.BeginPage(pageWidth, pageHeight);
    canvas.Clear(SKColors.White);
    canvas.Scale(contentScale);
    canvas.DrawPicture(picture);
    pdfDoc.EndPage();
    pdfDoc.Close();
    Console.WriteLine($"PDF created, size={new FileInfo("output.pdf").Length} bytes");
}

using (var xpsStream = File.Create("output.xps"))
{
    using var xpsDoc = SKDocument.CreateXps(xpsStream);
    if (xpsDoc == null) { Console.WriteLine("CreateXps returned null (not available)"); return; }
    using var canvas = xpsDoc.BeginPage(pageWidth, pageHeight);
    canvas.Clear(SKColors.White);
    canvas.Scale(contentScale);
    canvas.DrawPicture(picture);
    xpsDoc.EndPage();
    xpsDoc.Close();
    Console.WriteLine($"XPS created, size={new FileInfo("output.xps").Length} bytes");
}

